import { Button } from "@mui/material";
import Dialog from "@mui/material/Dialog";
import { MdClose } from "react-icons/md";

const ProducModal = (props) => {
  return (
    <>
      <Dialog
        open={true}
        className="productModal"
        onClose={() => props.closeProductModal(false)}
      >
        <Button
          className="close"
          onClick={() => props.closeProductModal(false)}
        >
          <MdClose />
        </Button>
        <h4 className="mb-0">
          MLB - Áo thun unisex cổ tròn tay ngắn phom suông hiện đại
        </h4>
        <div className="d-flex align-item-center">
          <div className="d-flex align-item-center">
            <span> Thương hiệu: </span>
            <span className="ml-2"> MLB </span>
          </div>
          <Rating name="read-only" value={value} readOnly />
        </div>
      </Dialog>
    </>
  );
};

export default ProducModal;
